jQuery.Class("Settings_SupportProcesses_Index_Js",{},{registerChangeVal:function(e){e.find(".configField").change(function(e){var t=$(e.currentTarget),s={};s.type=t.data("type"),s.param=t.attr("name"),"checkbox"==t.attr("type")?s.val=this.checked:s.val=null!=t.val()?t.val():"",app.saveAjax("updateConfig",s).then(function(e){Settings_Vtiger_Index_Js.showMessage({type:"success",text:e.result.message})})})},registerEvents:function(){var e=$(".supportProcessesContainer");this.registerChangeVal(e)}});